import{GAME_CONFIG}from"../config.js";import{battleRecorder}from"./BattleRecorder.js";import{AI}from"../ai/AI.js";import{TurnSimulator}from"./TurnSimulator.js";import{AnimationPlayer}from"../render/AnimationPlayer.js";import{audioManager}from"../audio/AudioManager.js";class TurnManager{constructor(t){this.game=t,this.calculatedScript={},this.simulator=new TurnSimulator(this.game),this.player=new AnimationPlayer(this.game),this.ai=new AI(this.game),this.planningTimerStartedAt=0,this.planningTimerActive=!1,this.autoStartTriggered=!1}initFirstTurn(){window.roundCount=1,gameState="PLANNING",this.resetPlanningTimer(),console.log("Фаза планирования. Раздайте приказы персонажам."),audioManager.play("start_battle",.2);var t=window.entities;let i=t.find(t=>"player"===t.type);t&&t.forEach(t=>{"player"!=t.type&&t.lookAt(i.q,i.r)})}startTurnExecution(){"PLANNING"===window.gameState&&(this.planningTimerActive=!1,this.autoStartTriggered=!0,this.ai.planAll(),this.realSimulationStartTime=performance.now(),this.calculatedScript=this.simulator.calculateRoundScript(window.entities),this.player.play(this.calculatedScript),window.gameState="EXECUTION")}updateExecution(){var t;"EXECUTION"!==window.gameState||this.player.updatePlayback()||(t=(performance.now()-this.realSimulationStartTime)/1e3,console.log(`%c[TurnManager]: Сценарий раунда успешно воспроизведен за ${t.toFixed(3)} сек.`,"color: #00ff00; font-weight: bold;"),this.endTurnExecution())}endTurnExecution(){console.log("[TurnManager]: Все персонажи добежали. Возврат в фазу планирования."),window.gameState="PLANNING",this.resetPlanningTimer(),this.removeDeadEntities(),window.entities&&window.entities.forEach(t=>{t.resetPlannedState()}),this.game.grid.plannedPath=[],this.game.grid.highlights=[],this.game.input._updateGridHighlights();var t=this.game.game.sceneManager.currentScene?.ui;t&&t.consoleUI&&(t.consoleUI.viewingRound=window.roundCount)}removeDeadEntities(){window.entities&&!window.entities.find(t=>"player"===t.type&&t.hp<=0)&&(window.entities=window.entities.filter(t=>{if(t){if(0<t.hp)return!0;t.actionQueue&&"function"==typeof t.actionQueue.clear&&t.actionQueue.clear()}return!1}))}resetPlanningTimer(){var t=GAME_CONFIG.turn.planningTimeLimit||0;this.planningTimerStartedAt=performance.now(),this.planningTimerActive=0<t,this.autoStartTriggered=!1}updatePlanning(){"PLANNING"===window.gameState&&this.planningTimerActive&&!this.autoStartTriggered&&this.getPlanningTimeLeftMs()<=0&&(this.autoStartTriggered=!0,console.log("[TurnManager]: Время планирования вышло. Автоматический запуск симуляции."),this.startTurnExecution())}getPlanningTimeLeftMs(){var t,i=GAME_CONFIG.turn.planningTimeLimit||0;return i<=0?0:(t=performance.now()-this.planningTimerStartedAt,Math.max(0,1e3*i-t))}getPlanningTimeLeftSeconds(){return Math.ceil(this.getPlanningTimeLeftMs()/1e3)}formatPlanningTime(){var t;return(GAME_CONFIG.turn.planningTimeLimit||0)<=0?"--:--":(t=this.getPlanningTimeLeftSeconds(),Math.floor(t/60)+":"+String(t%60).padStart(2,"0"))}isPlanningTimerWarning(){var t=GAME_CONFIG.turn.planningWarningTime||15;return"PLANNING"===window.gameState&&this.planningTimerActive&&this.getPlanningTimeLeftSeconds()<=t}}export{TurnManager};